import json

# Read the issues
issues_file = "/home/ketan/project/kapow/.beads/issues.jsonl"
issues = {}

with open(issues_file, 'r') as f:
    for line in f:
        if line.strip():
            issue = json.loads(line)
            issues[issue['id']] = issue

# Function to recursively print dependency tree
def print_tree(issue_id, visited=None, depth=0, prefix=""):
    if visited is None:
        visited = set()

    if issue_id in visited:
        return
    visited.add(issue_id)

    if issue_id not in issues:
        return

    issue = issues[issue_id]
    status_icon = "✓" if issue['status'] == 'done' else "○"
    print(f"{prefix}{status_icon} {issue_id}: {issue['title'][:50]}")

    # Find all issues that block this one
    blockers = []
    for other_id, other in issues.items():
        if other.get('dependencies'):
            for dep in other['dependencies']:
                if dep['type'] == 'blocks' and dep['depends_on_id'] == issue_id:
                    blockers.append(other_id)

    # Print blockers
    for i, blocker_id in enumerate(sorted(blockers)):
        is_last = i == len(blockers) - 1
        new_prefix = prefix + ("    " if is_last else "│   ")
        connector = "└── " if is_last else "├── "
        print(f"{prefix}{connector}", end="")
        # Recursive call with adjusted prefix
        blocker = issues[blocker_id]
        status_icon = "✓" if blocker['status'] == 'done' else "○"
        print(f"{status_icon} {blocker_id}: {blocker['title'][:50]}")

print("="*100)
print("DEPENDENCY TREE: kapow-jsuj (Admissions Importer)")
print("="*100)
print("\nShowing all issues that must be completed before kapow-jsuj:")
print("(Blockers of kapow-jsuj and their blockers, recursively)\n")

# Custom tree printer for blockers
def print_blocking_tree(issue_id, visited=None, depth=0):
    if visited is None:
        visited = set()

    if issue_id in visited or depth > 10:
        return
    visited.add(issue_id)

    if issue_id not in issues:
        return

    issue = issues[issue_id]
    indent = "  " * depth
    status_icon = "✓" if issue['status'] == 'done' else "○"

    print(f"{indent}{status_icon} {issue_id}: {issue['title']}")
    if depth == 0:
        print(f"{indent}   Status: {issue['status']}, Priority: P{issue.get('priority', '?')}")
        print(f"{indent}   Type: {issue['issue_type']}")

    # Find blockers
    blockers = []
    for other_id, other in issues.items():
        if other.get('dependencies'):
            for dep in other['dependencies']:
                if dep['type'] == 'blocks' and dep['depends_on_id'] == issue_id:
                    blockers.append(other_id)

    if blockers:
        if depth == 0:
            print(f"{indent}   Blockers (must complete first):")
        for blocker_id in sorted(blockers):
            print_blocking_tree(blocker_id, visited, depth + 1)

print_blocking_tree('kapow-jsuj')

# Now print the full scope of the epic
print("\n" + "="*100)
print("FULL EPIC TREE: kapow-o0j (Data Import Tool)")
print("="*100)
print("\nAll issues under the Data Import Tool epic:\n")

def get_children(issue_id):
    """Get all child issues"""
    children = []
    for other_id, issue in issues.items():
        if issue.get('dependencies'):
            for dep in issue['dependencies']:
                if dep['type'] == 'parent-child' and dep['depends_on_id'] == issue_id:
                    children.append(other_id)
    return sorted(children)

epic = issues['kapow-o0j']
print(f"Epic: {epic['id']} - {epic['title']}")
print(f"Status: {epic['status']}, Priority: P{epic.get('priority', '?')}")

children = get_children('kapow-o0j')
print(f"\nTotal child issues: {len(children)}\n")

# Group by priority
by_priority = {}
for child_id in children:
    child = issues[child_id]
    p = child.get('priority', 999)
    if p not in by_priority:
        by_priority[p] = []
    by_priority[p].append(child_id)

for priority in sorted(by_priority.keys()):
    print(f"Priority {priority}:")
    for child_id in by_priority[priority]:
        child = issues[child_id]
        status_icon = "✓" if child['status'] == 'done' else "○"
        print(f"  {status_icon} {child_id}: {child['title'][:60]} [{child['issue_type']}]")
    print()

