 1→package dbutil
 2→
 3→import (
 4→	"context"
 5→	"fmt"
 6→
 7→	"github.com/jackc/pgx/v5"
 8→	"github.com/jackc/pgx/v5/pgxpool"
 9→)
10→
11→// BatchQuery is a parameterized SQL statement with its arguments.
12→type BatchQuery struct {
13→	SQL  string
14→	Args []any
15→}
16→
17→// BatchExec sends all queries as a single pgx batch, executing them within one
18→// round-trip. Returns the first error encountered across all results.
19→func BatchExec(ctx context.Context, pool *pgxpool.Pool, queries []BatchQuery) error {
20→	if len(queries) == 0 {
21→		return nil
22→	}
23→
24→	batch := &pgx.Batch{}
25→	for _, q := range queries {
26→		batch.Queue(q.SQL, q.Args...)
27→	}
28→
29→	results := pool.SendBatch(ctx, batch)
30→	defer results.Close()
31→
32→	for i := range queries {
33→		if _, err := results.Exec(); err != nil {
34→			return fmt.Errorf("dbutil: batch exec query %d: %w", i, err)
35→		}
36→	}
37→	return nil
38→}
39→
40→// CopyFrom bulk-inserts rows into the given table using PostgreSQL's COPY
41→// protocol. Returns the number of rows inserted.
42→func CopyFrom(ctx context.Context, pool *pgxpool.Pool, tableName pgx.Identifier, columns []string, rows [][]any) (int64, error) {
43→	rowSrc := pgx.CopyFromRows(rows)
44→	n, err := pool.CopyFrom(ctx, tableName, columns, rowSrc)
45→	if err != nil {
46→		return 0, fmt.Errorf("dbutil: copy from %s: %w", tableName.Sanitize(), err)
47→	}
48→	return n, nil
49→}
