  1→package namematch
  2→
  3→import (
  4→	"encoding/json"
  5→	"math"
  6→	"os"
  7→	"sort"
  8→)
  9→
 10→// Candidate represents an institution available for fuzzy matching.
 11→type Candidate struct {
 12→	Name   string
 13→	UnitID string
 14→	State  string
 15→}
 16→
 17→// FuzzyResult pairs a candidate with its similarity score.
 18→type FuzzyResult struct {
 19→	Candidate
 20→	Score float64
 21→}
 22→
 23→// UnmatchedEntry records a name that could not be matched deterministically,
 24→// along with the best fuzzy candidates found.
 25→type UnmatchedEntry struct {
 26→	Name          string        `json:"name"`
 27→	StateHint     string        `json:"state_hint,omitempty"`
 28→	TopCandidates []FuzzyResult `json:"top_candidates"`
 29→}
 30→
 31→// FuzzyMatcher performs Jaro-Winkler fuzzy matching against a set of
 32→// institution candidates. Candidates are indexed by state for efficient
 33→// filtering when a state hint is available.
 34→type FuzzyMatcher struct {
 35→	all     []indexedCandidate
 36→	byState map[string][]indexedCandidate
 37→}
 38→
 39→// indexedCandidate stores a candidate alongside its pre-normalized name.
 40→type indexedCandidate struct {
 41→	Candidate
 42→	normalized string
 43→}
 44→
 45→// DefaultThreshold is the minimum Jaro-Winkler score for a match.
 46→const DefaultThreshold = 0.92
 47→
 48→// maxResults is the maximum number of candidates returned by Match.
 49→const maxResults = 5
 50→
 51→// NewFuzzyMatcher builds a FuzzyMatcher from the given candidates. Each
 52→// candidate's name is pre-normalized for efficient repeated comparisons.
 53→func NewFuzzyMatcher(candidates []Candidate) *FuzzyMatcher {
 54→	fm := &FuzzyMatcher{
 55→		all:     make([]indexedCandidate, len(candidates)),
 56→		byState: make(map[string][]indexedCandidate),
 57→	}
 58→	for i, c := range candidates {
 59→		ic := indexedCandidate{
 60→			Candidate:  c,
 61→			normalized: Normalize(c.Name),
 62→		}
 63→		fm.all[i] = ic
 64→		if c.State != "" {
 65→			fm.byState[c.State] = append(fm.byState[c.State], ic)
 66→		}
 67→	}
 68→	return fm
 69→}
 70→
 71→// Match returns the top candidates whose Jaro-Winkler similarity to name
 72→// exceeds DefaultThreshold, sorted by score descending. When stateHint is
 73→// non-empty, only candidates in that state are considered.
 74→func (fm *FuzzyMatcher) Match(name string, stateHint string) []FuzzyResult {
 75→	norm := Normalize(name)
 76→
 77→	candidates := fm.all
 78→	if stateHint != "" {
 79→		if sc, ok := fm.byState[stateHint]; ok {
 80→			candidates = sc
 81→		} else {
 82→			return nil
 83→		}
 84→	}
 85→
 86→	var results []FuzzyResult
 87→	for _, c := range candidates {
 88→		score := jaroWinkler(norm, c.normalized)
 89→		if score >= DefaultThreshold {
 90→			results = append(results, FuzzyResult{
 91→				Candidate: c.Candidate,
 92→				Score:     score,
 93→			})
 94→		}
 95→	}
 96→
 97→	sort.Slice(results, func(i, j int) bool {
 98→		return results[i].Score > results[j].Score
 99→	})
100→
101→	if len(results) > maxResults {
102→		results = results[:maxResults]
103→	}
104→	return results
105→}
106→
107→// WriteReport writes a JSON report of unmatched entries to the given path.
108→func WriteReport(path string, unmatched []UnmatchedEntry) error {
109→	data, err := json.MarshalIndent(unmatched, "", "  ")
110→	if err != nil {
111→		return err
112→	}
113→	return os.WriteFile(path, data, 0o644)
114→}
115→
116→// jaroWinkler computes the Jaro-Winkler similarity between two strings.
117→// Returns a value in [0, 1] where 1 means identical.
118→func jaroWinkler(s1, s2 string) float64 {
119→	j := jaro(s1, s2)
120→	if j == 0 {
121→		return 0
122→	}
123→
124→	// Winkler prefix bonus: up to 4 characters, scaling factor 0.1
125→	prefix := 0
126→	limit := 4
127→	if len(s1) < limit {
128→		limit = len(s1)
129→	}
130→	if len(s2) < limit {
131→		limit = len(s2)
132→	}
133→	for i := 0; i < limit; i++ {
134→		if s1[i] == s2[i] {
135→			prefix++
136→		} else {
137→			break
138→		}
139→	}
140→
141→	return j + float64(prefix)*0.1*(1-j)
142→}
143→
144→// jaro computes the Jaro similarity between two strings.
145→func jaro(s1, s2 string) float64 {
146→	if s1 == s2 {
147→		return 1
148→	}
149→	l1, l2 := len(s1), len(s2)
150→	if l1 == 0 || l2 == 0 {
151→		return 0
152→	}
153→
154→	// Match window: floor(max(|s1|,|s2|)/2) - 1
155→	maxLen := l1
156→	if l2 > maxLen {
157→		maxLen = l2
158→	}
159→	window := int(math.Floor(float64(maxLen)/2)) - 1
160→	if window < 0 {
161→		window = 0
162→	}
163→
164→	s1Matches := make([]bool, l1)
165→	s2Matches := make([]bool, l2)
166→
167→	matches := 0
168→	transpositions := 0
169→
170→	for i := 0; i < l1; i++ {
171→		lo := i - window
172→		if lo < 0 {
173→			lo = 0
174→		}
175→		hi := i + window + 1
176→		if hi > l2 {
177→			hi = l2
178→		}
179→		for j := lo; j < hi; j++ {
180→			if s2Matches[j] || s1[i] != s2[j] {
181→				continue
182→			}
183→			s1Matches[i] = true
184→			s2Matches[j] = true
185→			matches++
186→			break
187→		}
188→	}
189→
190→	if matches == 0 {
191→		return 0
192→	}
193→
194→	k := 0
195→	for i := 0; i < l1; i++ {
196→		if !s1Matches[i] {
197→			continue
198→		}
199→		for !s2Matches[k] {
200→			k++
201→		}
202→		if s1[i] != s2[k] {
203→			transpositions++
204→		}
205→		k++
206→	}
207→
208→	m := float64(matches)
209→	return (m/float64(l1) + m/float64(l2) + (m-float64(transpositions)/2)/m) / 3
210→}
